/**
 * @typedef {number[]} Point - [x, y, z]
 */

/**
 * @param {Point[]} points
 * @param {Point} target
 * @return {number}
 */
function solve(points, target) {
    /**
     * Converts a 3D point array to a unique string key.
     * @param {Point} p
     * @returns {string}
     */
    const pointToString = (p) => `${p[0]},${p[1]},${p[2]}`;

    /**
     * Calculates the midpoint of two points using floor division.
     * @param {Point} p1
     * @param {Point} p2
     * @returns {Point}
     */
    const calculateMidpoint = (p1, p2) => {
        return [
            Math.floor((p1[0] + p2[0]) / 2),
            Math.floor((p1[1] + p2[1]) / 2),
            Math.floor((p1[2] + p2[2]) / 2)
        ];
    };

    const targetString = pointToString(target);

    // allPointsSet stores all unique points found so far (Generation 0 up to k-1)
    const allPointsSet = new Set();

    // Initial population (Generation 0)
    for (const p of points) {
        allPointsSet.add(pointToString(p));
    }

    // Check Generation 0
    if (allPointsSet.has(targetString)) {
        return 0;
    }

    let k = 0;

    while (true) {
        k++;

        // Get the current pool of unique points available for pairing
        const currentPool = [];
        for (const pStr of allPointsSet) {
            const coords = pStr.split(',').map(Number);
            currentPool.push(coords);
        }

        const newPointsSet = new Set();
        let generatedNewPoint = false;

        // Generate points for Generation k by pairing distinct points from the pool
        const N = currentPool.length;
        if (N < 2) {
            // Cannot generate any new points
            return -1;
        }

        for (let i = 0; i < N; i++) {
            for (let j = i + 1; j < N; j++) {
                const p1 = currentPool[i];
                const p2 = currentPool[j];

                // Since we are iterating over distinct elements from the Set, 
                // their coordinates are guaranteed to be different, satisfying the distinctness constraint.

                const midpoint = calculateMidpoint(p1, p2);
                const midpointStr = pointToString(midpoint);

                // Only consider points that haven't been found before
                if (!allPointsSet.has(midpointStr)) {
                    newPointsSet.add(midpointStr);
                    generatedNewPoint = true;
                }
            }
        }

        if (!generatedNewPoint) {
            // No new unique points were generated in this step, so the target won't be reached later.
            return -1;
        }

        // Check if the target was generated in this step
        if (newPointsSet.has(targetString)) {
            return k;
        }

        // Add all newly generated points to the master set for the next generation's pool
        for (const newPointStr of newPointsSet) {
            allPointsSet.add(newPointStr);
        }

        // Safety break (though bounded by 7^3 unique points)
        if (k > 350) return -1;
    }
}

