package main

import (
	"fmt"
	"strconv"
	"strings"
)

// Point representation for convenience, though we use string keys in the map.
type Point []int64

// pointToString converts a 3D point array to a unique string key "x,y,z".
func pointToString(p Point) string {
	s := make([]string, 3)
	for i := 0; i < 3; i++ {
		s[i] = strconv.FormatInt(p[i], 10)
	}
	return strings.Join(s, ",")
}

// calculateMidpoint calculates the floor of the midpoint of two points.
func calculateMidpoint(p1, p2 Point) Point {
	// Since all coordinates are non-negative, standard integer division performs floor division.
	return Point{
		(p1[0] + p2[0]) / 2,
		(p1[1] + p2[1]) / 2,
		(p1[2] + p2[2]) / 2,
	}
}

// solve finds the minimum generation k required to obtain the target point.
func solve(points [][]int64, target []int64) int64 {
	targetPoint := Point(target)
	targetString := pointToString(targetPoint)

	// allPointsSet stores all unique points found so far (Generation 0 up to k-1) using string keys.
	allPointsSet := make(map[string]struct{})

	// 1. Check Generation 0
	for _, p := range points {
		pPoint := Point(p)
		pStr := pointToString(pPoint)
		allPointsSet[pStr] = struct{}{}
		if pStr == targetString {
			return 0
		}
	}

	// If there are fewer than 2 unique initial points, we can never generate new points.
	if len(allPointsSet) < 2 {
		return -1
	}

	k := int64(0)

	for {
		k++

		// 2. Get the current pool of unique points available for pairing.
		// We convert map keys back to Point arrays for easy arithmetic.
		currentPool := make([]Point, 0, len(allPointsSet))
		for pStr := range allPointsSet {
			coordsStr := strings.Split(pStr, ",")
			p := make(Point, 3)
			for i := 0; i < 3; i++ {
				val, _ := strconv.ParseInt(coordsStr[i], 10, 64)
				p[i] = val
			}
			currentPool = append(currentPool, p)
		}

		newPointsSet := make(map[string]struct{})
		generatedNewPoint := false

		N := len(currentPool)
		if N < 2 {
			// Should ideally not happen if we handled the initial state correctly, 
			// but serves as a safety break.
			return -1
		}

		// 3. Generate points for Generation k by pairing distinct points from the pool.
		for i := 0; i < N; i++ {
			for j := i + 1; j < N; j++ {
				p1 := currentPool[i]
				p2 := currentPool[j]

				// Calculate midpoint
				midpoint := calculateMidpoint(p1, p2)
				midpointStr := pointToString(midpoint)

				// Only consider points that haven't been found before (i.e., not in allPointsSet)
				if _, found := allPointsSet[midpointStr]; !found {
					// Check if the target was generated
					if midpointStr == targetString {
						return k
					}

					// Add to the set of newly generated points for this generation
					newPointsSet[midpointStr] = struct{}{}
					generatedNewPoint = true
				}
			}
		}

		// 4. Termination checks
		if !generatedNewPoint {
			// No new unique points were generated in this step, so the target won't be reached later.
			return -1
		}

		// 5. Update master set for the next generation's pool
		for newPointStr := range newPointsSet {
			allPointsSet[newPointStr] = struct{}{}
		}
	}
}
